#!/usr/bin/env python3
import base64, os
os.makedirs("ssot/core", exist_ok=True)
ar = base64.b64decode('')
pr = base64.b64decode('')
open("ssot/core/ACTION_REGISTRY.yaml","wb").write(ar)
print("[ok] ACTION_REGISTRY.yaml")
open("ssot/core/PAIN_REGISTRY.yaml","wb").write(pr)
print("[ok] PAIN_REGISTRY.yaml")
import subprocess
r = subprocess.run(["git","add","ssot/core/"], capture_output=True)
r = subprocess.run(["git","commit","-m","feat(lote-u): ACTION_REGISTRY + PAIN_REGISTRY"], capture_output=True)
print(r.stdout.decode())
r = subprocess.run(["git","push"], capture_output=True)
print("push:", r.returncode)
import subprocess as sp
sp.run(["python3","scripts/gate_pass_strict.py"])
